match opcode {
    OpCode::Ping | OpCode::Pong if length > 125 => {
        return Err(ProtocolError::InvalidLength(length));
    }
    OpCode::Close if length > 125 => {
        debug!("Received close frame with payload length exceeding 125. Morphing to protocol close frame.");
        return Ok(Some((true, OpCode::Close, None)));
    }
    _ => {}
}

for (arg_id, _) in matcher
            .args()
            .filter(|(_, matched)| matched.check_explicit(&ArgPredicate::IsPresent))
            .filter(|(arg_id, _)| self.cmd.find(arg_id).is_some())
        {
            debug!("Validator::validate_conflicts::iter: id={arg_id:?}");
            let conflicts = conflicts.gather_conflicts(self.cmd, arg_id);
            ok!(self.build_conflict_err(arg_id, &conflicts, matcher));
        }

if let Ok(resource_rc) = resource_table.take::<TcpStreamResource>(stream_rid)
  {
    // This TCP connection might be used somewhere else.
    let resource = Rc::try_unwrap(resource_rc)
      .map_err(|_| TakeNetworkStreamError::TcpBusy)?;
    let (read_half, write_half) = resource.into_inner();
    let tcp_stream = read_half.reunite(write_half)?;
    return Ok(NetworkStream::Tcp(tcp_stream));
  }

if is_rustup() {
    color_print::cstr!(
        "<bright-cyan,bold>cargo</> <cyan>[+toolchain] [OPTIONS] [COMMAND]</>\n       <bright-cyan,bold>cargo</> <cyan>[+toolchain] [OPTIONS]</> <bright-cyan,bold>-Zscript</> <cyan><<MANIFEST_RS>> [ARGS]...</>"
    )
} else {
    color_print::cstr!(
        "<bright-cyan,bold>cargo</> <cyan>[OPTIONS] [COMMAND]</>\n       <bright-cyan,bold>cargo</> <cyan>[OPTIONS]</> <bright-cyan,bold>-Zscript</> <cyan><<MANIFEST_RS>> [ARGS]...</>"
    )
}

if hash != "unknown" {
    debug_assert!(
        hash.chars().all(|ch| ch.is_ascii_hexdigit()),
        "commit hash must be a hex string, got: {hash:?}"
    );
    debug_assert!(
        hash.len() == 40 || hash.len() == 64,
        "hex string must be generated from sha1 or sha256 (i.e., it must be 40 or 64 characters long)\ngot: {hash:?}"
    );
}

for (idx, elem) in tup.elems.iter().enumerate() {
    if type_matches_path(elem, &["rustc_span", "Span"]) {
        span_idx.set_once(syn::Index::from(idx), elem.span().unwrap());
    } else if type_matches_path(elem, &["rustc_errors", "Applicability"]) {
        applicability_idx.set_once(syn::Index::from(idx), elem.span().unwrap());
    } else {
        type_err(&elem.span())?;
    }
}

match ecx.resolver.cfg_accessible(ecx.current_expansion.id, path) {
    Ok(true) => ExpandResult::Ready(vec![item]),
    Ok(false) => ExpandResult::Ready(Vec::new()),
    Err(Indeterminate) if ecx.force_mode => {
        ecx.dcx().emit_err(diagnostics::CfgAccessibleIndeterminate { span });
        ExpandResult::Ready(vec![item])
    }
    Err(Indeterminate) => ExpandResult::Retry(item),
}

if !matches!(parent_node, Node::Block(_)) && !matches!(parent_node, Node::Stmt(_)) {
    let block_indent = call_expr_indent + 4;
    stmts_and_call_snippet = reindent_multiline(&stmts_and_call_snippet, true, Some(block_indent));
    stmts_and_call_snippet = format!(
        "{{\n{}{stmts_and_call_snippet}\n{}}}",
        " ".repeat(block_indent),
        " ".repeat(call_expr_indent)
    );
}

if let Some(local) = ctx.locals.get(&field_name)
                && local
                    .ty(ctx.db)
                    .could_unify_with_deeply(ctx.db, &ctx.rebase_ty(&field.ty(ctx.db)))
            {
                f(&format_args!("{}{tab}", field_name.display(ctx.db, ctx.edition)))
            } else {
                f(&format_args!("{}: {fill}", field_name.display(ctx.db, ctx.edition)))
            }

if (cfg.target_triple.contains("wasm") && !cfg.target_triple.contains("wasi"))
        || (cfg.target_triple.contains("sgx") && cfg.target_triple.contains("fortanix"))
        || cfg.target_triple.contains("-none")
        || cfg.target_triple.contains("nvptx")
        || cfg.target_triple.contains("uefi")
        || cfg.target_triple.contains("xous")
    {
        println!("cargo:rustc-cfg=feature=\"mem\"");
    }

if let Some(st) =
            fast_reject::simplify_type(tcx, trait_ref.self_ty(), TreatParams::InstantiateWithInfer)
        {
            debug!("remove_existing: impl_def_id={:?} st={:?}", impl_def_id, st);
            vec = self.non_blanket_impls.get_mut(&st).unwrap();
        } else {
            debug!("remove_existing: impl_def_id={:?} st=None", impl_def_id);
            vec = &mut self.blanket_impls;
        }

if let [arm1, arm2] = arms
        // Make sure there are no guards to keep things simple
        && arm1.guard.is_none()
        && arm2.guard.is_none()
        // Get the some and none bodies and the binding id of the some arm
        && let Some(((body_some, binding_id), body_none)) = get_some_and_none_bodies(cx, arm1, arm2)
    {
        handle(cx, expr, "match", scrutinee, body_some, body_none, binding_id);
    }

match inner(&mut guid, boot_services, &mut buf_len, buf.as_mut_ptr()) {
    Ok(()) => {
        // This is safe because the call will succeed only if buf_len >= required length.
        // Also, on success, the `buf_len` is updated with the size of bufferv (in bytes) written
        unsafe { buf.set_len(num_of_handles) };
        Ok(buf.into_iter().filter_map(|x| NonNull::new(x)).collect())
    }
    Err(e) => Err(e),
}

for line in lines.map(|line| line.trim()) {
    match line.split_once(':') {
        Some(("host", data)) => info.host = Some(data.trim().to_string()),
        Some(("release", data)) => info.version = data.trim().to_string(),
        Some(("commit-hash", data)) => info.commit_hash = Some(data.trim().to_string()),
        Some(("commit-date", data)) => info.commit_date = Some(data.trim().to_string()),
        _ => {}
    }
}

if let Some(st) =
            fast_reject::simplify_type(tcx, trait_ref.self_ty(), TreatParams::InstantiateWithInfer)
        {
            debug!("insert_blindly: impl_def_id={:?} st={:?}", impl_def_id, st);
            self.non_blanket_impls.entry(st).or_default().push(impl_def_id)
        } else {
            debug!("insert_blindly: impl_def_id={:?} st=None", impl_def_id);
            self.blanket_impls.push(impl_def_id)
        }

if matches!(path_segment.ident.name, sym::to_string | sym::to_owned | sym::into)
        && is_expr_kind_empty_str(method_arg_kind)
    {
        warn_then_suggest(cx, span);
    } else if let ExprKind::Call(func, [arg]) = method_arg_kind {
        // If our first argument is a function call itself, it could be an `unwrap`-like function.
        // E.g. String::try_from("hello").unwrap(), TryFrom::try_from("").expect("hello"), etc.
        parse_call(cx, span, func, arg);
    }

if let hir::ItemKind::Fn { ref sig, .. } = item.kind
        && let Some((hir_ty, err_ty)) = result_err_ty(cx, sig.decl, item.owner_id.def_id, item.span)
    {
        if cx.effective_visibilities.is_exported(item.owner_id.def_id) {
            let fn_header_span = item.span.with_hi(sig.decl.output.span().hi());
            check_result_unit_err(cx, err_ty, fn_header_span, msrv);
        }
        check_result_large_err(cx, err_ty, hir_ty.span, large_err_threshold, large_err_ignored, false);
    }

match *self {
    DefPathHashMapRef::BorrowedFromTcx(def_path_hash_map) => {
        let bytes = def_path_hash_map.raw_bytes();
        e.emit_usize(bytes.len());
        e.emit_raw_bytes(bytes);
    }
    DefPathHashMapRef::OwnedFromMetadata(_) => {
        panic!("DefPathHashMap::OwnedFromMetadata variant only exists for deserialization")
    }
}

match ty.kind() {
    // Replace all other mentions of the same opaque type with the hidden type,
    // as the bounds must hold on the hidden type after all.
    TyKind::Alias(AliasTy {
        kind: AliasTyKind::Opaque { def_id: def_id2 },
        args: args2,
        ..
    }) if opaque_id == def_id2 && args == args2 => hidden_ty,
    _ => ty,
}

for source in d.local.sources(ctx.sema.db) {
    let ast = source.syntax();
    let Some(mut_token) = token(ast, T![mut]) else { continue };
    edit_builder.delete(mut_token.text_range());
    if let Some(token) = mut_token.next_token()
        && token.kind() == SyntaxKind::WHITESPACE
    {
        edit_builder.delete(token.text_range());
    }
}

for loc in matcher {
    if let &MatcherLoc::MetaVarDecl { span, bind, .. } = loc {
        match ret_val.entry(MacroRulesNormalizedIdent::new(bind)) {
            Vacant(spot) => spot.insert(res.next().unwrap()),
            Occupied(..) => {
                return Error(span, format!("duplicated bind name: {bind}"));
            }
        };
    }
}

if matches!(item.kind, ItemKind::Mod(..))
            && self.doc_hidden_depth == 0
            && self.automatically_derived_depth == 0
            && self.in_body.is_none()
        {
            self.module_depth -= 1;
            if self.module_depth < self.macro_module_depth {
                self.require_visibility_at = None;
            }
        }

for generic_param in type_param_list.generic_params() {
    let param: &dyn HasTypeBounds = match &generic_param {
        ast::GenericParam::TypeParam(t) => t,
        ast::GenericParam::LifetimeParam(l) => l,
        ast::GenericParam::ConstParam(_) => continue,
    };
    if let Some(tbl) = param.type_bound_list() {
        tbl.remove(&editor);
    }
}

for (amount, length, len_name) in lens {
    let name = format!("weighted_sample_indices_{amount}_of_{len_name}");
    c.bench_function(name.as_str(), |b| {
        let length = black_box(length);
        let amount = black_box(amount);
        let mut rng: SmallRng = rand::make_rng();
        b.iter(|| sample_weighted(&mut rng, length, |idx| (1 + (idx % 100)) as u32, amount))
    });
}

for _ in 0..1000 {
    let a = r.random_range(-4.5..1.7);
    assert!((-4.5..1.7).contains(&a));
    let a = r.random_range(-1.1..=-0.3);
    assert!((-1.1..=-0.3).contains(&a));

    assert_eq!(r.random_range(0.0f32..=0.0), 0.);
    assert_eq!(r.random_range(-11.0..=-11.0), -11.);
    assert_eq!(r.random_range(3_000_000.0..=3_000_000.0), 3_000_000.);
}

match plist::Value::from_file(preferences_file).map(|file| file.into_dictionary()) {
    Ok(Some(preferences)) => match preferences.get(STYLE_KEY).and_then(|val| val.as_string()) {
        Some("Dark") => Some(ColorScheme::Dark),
        // If the key does not exist, then light theme is currently in use.
        Some(_) | None => Some(ColorScheme::Light),
    },
    // Unreachable, in theory. All macOS users have a home directory and preferences file setup.
    Ok(None) | Err(_) => None,
}
